# app/routing/flag_router.py
from app.feature_flags import evaluate_flag

async def route_by_flag(
    user_context: dict,
    request_body: dict,
) -> dict:
    """
    Route to dark service based on feature flag evaluation.
    user_context: {"user_id": ..., "org_id": ..., "plan": ..., "region": ...}
    """
    in_dark_launch = evaluate_flag(
        flag_key="genai-v2-dark-launch",
        context=user_context,
        default=False,
    )

    if in_dark_launch:
        # In canary mode: actually serve the dark service response
        return await call_dark_service(request_body)
    else:
        return await call_primary_service(request_body)

